/**
 * Self-contained reducer test for the advisory allocation kernel.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/advisory-allocation-kernel.test.ts
 */

import assert from 'node:assert';
import {
  ADVISORY_ALLOCATION_KERNEL_THEOREM_IDS,
  commitPointReached,
  createSyntheticVisibleObservation,
  deriveAdvisoryAllocationKernel,
  type AdvisoryAllocationKernelInput,
} from '../advisory-allocation-kernel';

const BASE_INPUT: AdvisoryAllocationKernelInput = {
  generatedAt: '2026-04-10T00:00:00.000Z',
  source: 'test-suite',
  plan: {
    pointIds: ['market-ready'],
    samplesPerPoint: 1,
    maxAttemptsPerPoint: 1,
  },
  points: [
    {
      pointId: 'market-ready',
      accepted: 1,
      rejected: 0,
      observed: 1,
    },
  ],
  modelSolved: true,
  ingestLocked: true,
  frame: {
    observation: createSyntheticVisibleObservation(910, 650),
    currentPrice: 100_200,
    lastPrice: 100_150,
    displayedDepth: 3,
    elapsedSinceUpdateMs: 4,
    maxObservationAgeMs: 25,
    decayPerMs: 5,
    priceMoveThreshold: 80,
  },
  candidateIds: [7, 3],
  risk: {
    inventoryExposure: 4_000,
    inventoryLimit: 10_000,
    openOrderCount: 0,
    openOrderLimit: 1,
  },
  budget: {
    deadlineMs: 20,
    elapsedMs: 4,
    commitNumerator: 9,
    commitDenominator: 10,
  },
};

const deterministicA = deriveAdvisoryAllocationKernel(BASE_INPUT);
const deterministicB = deriveAdvisoryAllocationKernel({
  ...BASE_INPUT,
  candidateIds: [...BASE_INPUT.candidateIds].reverse(),
});

assert.deepStrictEqual(deterministicA, deterministicB);
assert.strictEqual(deterministicA.generatedAt, '2026-04-10T00:00:00.000Z');
assert.strictEqual(deterministicA.source, 'test-suite');
assert.deepStrictEqual(deterministicA.decision, {
  kind: 'allocate',
  candidateId: 3,
});
assert.strictEqual(deterministicA.aggregate.priceMove, 50);
assert.strictEqual(deterministicA.aggregate.confidenceDecay, 20);
assert.strictEqual(deterministicA.aggregate.decayedConfidenceScore, 890);
assert.strictEqual(deterministicA.aggregate.observationFresh, true);
assert.strictEqual(deterministicA.aggregate.stabilityWitness, true);
assert.strictEqual(deterministicA.aggregate.riskWithinLimits, true);
assert.strictEqual(deterministicA.aggregate.marketReady, true);
assert.strictEqual(deterministicA.aggregate.withinBudget, true);
assert.strictEqual(deterministicA.aggregate.commitPointReached, false);
assert.strictEqual(deterministicA.aggregate.confidenceFloorSatisfied, true);
assert.deepStrictEqual(deterministicA.aggregate.certifiedBridgeDecision, {
  kind: 'allocate',
  candidateId: 3,
});

for (const theoremId of ADVISORY_ALLOCATION_KERNEL_THEOREM_IDS) {
  assert.ok(deterministicA.theoremIds.includes(theoremId));
}

assert.strictEqual(
  commitPointReached({
    deadlineMs: 20,
    elapsedMs: 18,
    commitNumerator: 9,
    commitDenominator: 10,
  }),
  true
);

const staleObservation = deriveAdvisoryAllocationKernel({
  ...BASE_INPUT,
  frame: {
    ...BASE_INPUT.frame,
    elapsedSinceUpdateMs: 40,
  },
});
assert.deepStrictEqual(staleObservation.decision, {
  kind: 'safe-state',
  reason: 'stale-observation',
});

const decayedBelowFloor = deriveAdvisoryAllocationKernel({
  ...BASE_INPUT,
  frame: {
    ...BASE_INPUT.frame,
    observation: createSyntheticVisibleObservation(700, 650),
    elapsedSinceUpdateMs: 11,
    decayPerMs: 5,
  },
});
assert.deepStrictEqual(decayedBelowFloor.decision, {
  kind: 'safe-state',
  reason: 'stale-observation',
});

const adverseSelection = deriveAdvisoryAllocationKernel({
  ...BASE_INPUT,
  frame: {
    ...BASE_INPUT.frame,
    currentPrice: 100_400,
    lastPrice: 100_100,
    displayedDepth: 0,
    priceMoveThreshold: 50,
  },
});
assert.deepStrictEqual(adverseSelection.decision, {
  kind: 'safe-state',
  reason: 'adverse-selection',
});

const riskLimited = deriveAdvisoryAllocationKernel({
  ...BASE_INPUT,
  risk: {
    inventoryExposure: 15_000,
    inventoryLimit: 10_000,
    openOrderCount: 0,
    openOrderLimit: 1,
  },
});
assert.deepStrictEqual(riskLimited.decision, {
  kind: 'safe-state',
  reason: 'risk-limit-reached',
});

const commitFailClosed = deriveAdvisoryAllocationKernel({
  ...BASE_INPUT,
  ingestLocked: false,
  budget: {
    deadlineMs: 20,
    elapsedMs: 18,
    commitNumerator: 9,
    commitDenominator: 10,
  },
});
assert.deepStrictEqual(commitFailClosed.decision, {
  kind: 'safe-state',
  reason: 'deadline-exceeded',
});

console.log('advisory-allocation-kernel: all tests passed');
